const express = require('express');
const { MongoClient, ObjectId } = require('mongodb');

const app = express();
app.use(express.json());

const MONGODB_URI = process.env.MONGODB_URI || 'mongodb://localhost:27017';
const DB_NAME = process.env.DB_NAME || 'queryservice';

let db;

MongoClient.connect(MONGODB_URI, { useUnifiedTopology: true })
  .then(client => {
    db = client.db(DB_NAME);
    console.log('Connected to MongoDB');
  })
  .catch(err => console.error('MongoDB connection error:', err));

const ALLOWED_OPERATORS = [
  '$eq', '$ne', '$gt', '$gte', '$lt', '$lte',
  '$in', '$nin', '$exists', '$type', '$regex',
  '$and', '$or', '$not', '$nor', '$all',
  '$elemMatch', '$size', '$mod'
];

const DANGEROUS_OPERATORS = [
  '$where', '$function', '$accumulator', '$expr',
  '$jsonSchema', '$text'
];

function sanitizeQuery(query) {
  if (query === null || query === undefined) {
    return query;
  }

  if (typeof query !== 'object') {
    return query;
  }

  if (Array.isArray(query)) {
    return query.map(item => sanitizeQuery(item));
  }

  const sanitized = {};

  for (const [key, value] of Object.entries(query)) {
    if (DANGEROUS_OPERATORS.includes(key)) {
      continue;
    }

    if (key.startsWith('$')) {
      if (!ALLOWED_OPERATORS.includes(key)) {
        continue;
      }

      if (key === '$regex') {
        if (typeof value === 'string') {
          try {
            sanitized[key] = value.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
          } catch (e) {
            continue;
          }
        } else if (value instanceof RegExp) {
          sanitized[key] = value.source.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
        }
        continue;
      }

      sanitized[key] = sanitizeQuery(value);
    } else {
      if (key.includes('.') && key.split('.').some(part => part.startsWith('$'))) {
        continue;
      }

      sanitized[key] = sanitizeQuery(value);
    }
  }

  return sanitized;
}

function validateAndSanitizeFilter(filter) {
  if (!filter || typeof filter !== 'object' || Array.isArray(filter)) {
    return {};
  }

  return sanitizeQuery(filter);
}

function sanitizeOptions(options) {
  const sanitized = {};

  if (options.limit && typeof options.limit === 'number' && options.limit > 0) {
    sanitized.limit = Math.min(options.limit, 1000);
  } else {
    sanitized.limit = 100;
  }

  if (options.skip && typeof options.skip === 'number' && options.skip >= 0) {
    sanitized.skip = options.skip;
  }

  if (options.sort && typeof options.sort === 'object') {
    sanitized.sort = {};
    for (const [key, value] of Object.entries(options.sort)) {
      if (!key.startsWith('$') && (value === 1 || value === -1)) {
        sanitized.sort[key] = value;
      }
    }
  }

  if (options.projection && typeof options.projection === 'object') {
    sanitized.projection = {};
    for (const [key, value] of Object.entries(options.projection)) {
      if (!key.startsWith('$') && (value === 0 || value === 1)) {
        sanitized.projection[key] = value;
      }
    }
  }

  return sanitized;
}

app.post('/api/query/:collection', async (req, res) => {
  try {
    const { collection } = req.params;
    const { filter = {}, options = {} } = req.body;

    if (!collection || !/^[a-zA-Z0-9_]+$/.test(collection)) {
      return res.status(400).json({ error: 'Invalid collection name' });
    }

    const sanitizedFilter = validateAndSanitizeFilter(filter);
    const sanitizedOptions = sanitizeOptions(options);

    const coll = db.collection(collection);
    
    const results = await coll
      .find(sanitizedFilter)
      .limit(sanitizedOptions.limit)
      .skip(sanitizedOptions.skip || 0)
      .sort(sanitizedOptions.sort || {})
      .project(sanitizedOptions.projection || {})
      .toArray();

    const total = await coll.countDocuments(sanitizedFilter);

    res.json({
      success: true,
      data: results,
      count: results.length,
      total: total,
      filter: sanitizedFilter
    });

  } catch (error) {
    console.error('Query error:', error);
    res.status(500).json({ error: 'Query execution failed', message: error.message });
  }
});

